package io.github.wesleyosantos91.api.v1.mapper;

import io.github.wesleyosantos91.api.v1.request.PersonRequest;
import io.github.wesleyosantos91.api.v1.response.PersonResponse;
import io.github.wesleyosantos91.core.domain.PersonDomain;
import java.util.ArrayList;
import java.util.List;

public class PersonHttpMapper {

    private PersonHttpMapper() {
    }

    public static PersonDomain toDomain(PersonRequest request) {
        return new PersonDomain(null, request.getName(), request.getDateOfBirth(), request.getCpf(), request.getEmail());
    }

    public static PersonRequest toRequest(PersonDomain domain) {
        return new PersonRequest(domain.getName(), domain.getDateOfBirth(), domain.getCpf(), domain.getEmail());
    }

    public static PersonDomain toDomain(PersonResponse response) {
        return new PersonDomain(response.getId(), response.getName(), response.getDateOfBirth(), response.getCpf(), response.getEmail());
    }

    public static PersonResponse toResponse(PersonDomain domain) {
        return new PersonResponse(domain.getId(), domain.getName(), domain.getDateOfBirth(), domain.getCpf(), domain.getEmail());
    }

    public static List<PersonResponse> toListResponse(List<PersonDomain> domains) {
        List<PersonResponse> list = new ArrayList<>();
        domains.forEach(d -> list.add(toResponse(d)));
        return list;
    }
}

